import{_ as a,c as n,o as l,ag as e}from"./chunks/framework.B-XtCDNB.js";const F=JSON.parse('{"title":"FlashQL","description":"","frontmatter":{},"headers":[],"relativePath":"flashql.md","filePath":"flashql.md"}'),o={name:"flashql.md"};function p(t,s,r,c,i,y){return l(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="flashql" tabindex="-1">FlashQL <a class="header-anchor" href="#flashql" aria-label="Permalink to &quot;FlashQL&quot;">​</a></h1><p><em>A full SQL runtime for the local process, the browser, the edge, and the offline world.</em></p><p>FlashQL is LinkedQL&#39;s embeddable database engine: a complete in-process SQL runtime that runs anywhere JavaScript does, including Node.js, the browser, workers, and edge runtimes.</p><p>FlashQL brings together:</p><ul><li>SQL parsing and execution</li><li>transactional local storage</li><li>live queries</li><li>WAL and changefeed access</li><li>federation over foreign data</li><li>local materialization and realtime mirroring</li><li>point-in-time boot through version-aware replay</li></ul><h2 id="why-flashql-exists" tabindex="-1">Why FlashQL exists <a class="header-anchor" href="#why-flashql-exists" aria-label="Permalink to &quot;Why FlashQL exists&quot;">​</a></h2><p>Modern applications increasingly need database power in places where a traditional database server is inconvenient, expensive, unavailable, or simply the wrong abstraction.</p><p>Sometimes you want:</p><ul><li>a real query engine inside the app itself</li><li>a local store that survives network loss</li><li>one relational graph that spans local and remote data</li><li>reactivity over query results, not just table events</li><li>the ability to materialize or keep remote relations hot locally</li></ul><p>Just spin up an instance in-app and run SQL:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 2::text AS value</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ value: &#39;2&#39; }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is the smallest useful FlashQL shape:</p><ul><li>create the client</li><li>connect it</li><li>run SQL</li><li>disconnect it</li></ul><h2 id="what-flashql-is-good-at" tabindex="-1">What FlashQL is good at <a class="header-anchor" href="#what-flashql-is-good-at" aria-label="Permalink to &quot;What FlashQL is good at&quot;">​</a></h2><p>FlashQL is especially strong when you need one or more of these:</p><ul><li>a SQL runtime embedded inside an app, worker, or edge process</li><li>a persistent local-first data layer</li><li>live queries over local state</li><li>one query space spanning local and remote relations</li><li>explicit control over federation, materialization, and realtime mirroring</li><li>point-in-time boot and version-bound execution</li></ul><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>FlashQL is ephemeral by default, but it becomes a persistent local runtime when you attach a <code>keyval</code> backend.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> IndexedDBKV</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@webqit/keyval/indexeddb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  keyval</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> IndexedDBKV</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> path</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">my-app</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With a <code>keyval</code> backend:</p><ul><li>schema and data can survive reloads</li><li>WAL history can be persisted</li><li>sync state can be persisted</li><li>FlashQL becomes appropriate for browser PWAs and local-first applications</li></ul><p>Without a persistence backend, the engine is still useful for tests, ephemeral sessions, and in-process computation, but the state disappears when the process ends.</p><h2 id="dialects" tabindex="-1">Dialects <a class="header-anchor" href="#dialects" aria-label="Permalink to &quot;Dialects&quot;">​</a></h2><p>FlashQL supports both PostgreSQL-flavored and MySQL-flavored SQL.</p><p>Set a default dialect at the client level:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Optionally override it per query:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT \`name\` FROM \`users\`</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mysql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Where not specified, FlashQL defaults to <code>postgres</code>.</p><h2 id="compatibility-in-practice" tabindex="-1">Compatibility in practice <a class="header-anchor" href="#compatibility-in-practice" aria-label="Permalink to &quot;Compatibility in practice&quot;">​</a></h2><p>FlashQL speaks real SQL, but it is not trying to be a byte-for-byte clone of PostgreSQL or MySQL.</p><p>The goal is to cover the application-facing surface of SQL that actually matters in code:</p><ul><li>queries</li><li>mutations</li><li>schema operations</li><li>expressions</li><li>relational composition</li></ul><p>It also adds LinkedQL-specific capabilities such as DeepRefs, version binding, and structured JSON-style language features.</p><p>See the <a href="/flashql/lang">FlashQL Language Reference</a> for the current documented surface.</p><p>Two advanced PostgreSQL-flavored examples give a sense of scope:</p><hr><details><summary>Query 1: writable CTEs, LATERAL joins, aggregates, and windows</summary><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> rows </span><span style="color:#89DDFF;">}</span><span style="color:#89DDFF;"> =</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  \`</span><span style="color:#C3E88D;">WITH</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">      updated AS (</span></span>
<span class="line"><span style="color:#C3E88D;">        UPDATE users</span></span>
<span class="line"><span style="color:#C3E88D;">        SET status = &#39;inactive&#39;</span></span>
<span class="line"><span style="color:#C3E88D;">        WHERE last_login &lt; NOW() - INTERVAL &#39;90 days&#39;</span></span>
<span class="line"><span style="color:#C3E88D;">        RETURNING id, name, department, last_login</span></span>
<span class="line"><span style="color:#C3E88D;">      ),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">      metrics AS (</span></span>
<span class="line"><span style="color:#C3E88D;">        SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">          u.id,</span></span>
<span class="line"><span style="color:#C3E88D;">          u.name,</span></span>
<span class="line"><span style="color:#C3E88D;">          u.department,</span></span>
<span class="line"><span style="color:#C3E88D;">          m.avg_total,</span></span>
<span class="line"><span style="color:#C3E88D;">          m.order_rank</span></span>
<span class="line"><span style="color:#C3E88D;">        FROM updated u</span></span>
<span class="line"><span style="color:#C3E88D;">        LEFT JOIN LATERAL (</span></span>
<span class="line"><span style="color:#C3E88D;">          SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">            AVG(total) AS avg_total,</span></span>
<span class="line"><span style="color:#C3E88D;">            RANK() OVER (ORDER BY SUM(total) DESC) AS order_rank</span></span>
<span class="line"><span style="color:#C3E88D;">          FROM orders o</span></span>
<span class="line"><span style="color:#C3E88D;">          WHERE o.user_id = u.id</span></span>
<span class="line"><span style="color:#C3E88D;">          GROUP BY o.user_id</span></span>
<span class="line"><span style="color:#C3E88D;">        ) m ON TRUE</span></span>
<span class="line"><span style="color:#C3E88D;">      ),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">      aggregates AS (</span></span>
<span class="line"><span style="color:#C3E88D;">        SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">          department,</span></span>
<span class="line"><span style="color:#C3E88D;">          COUNT(*) AS user_count,</span></span>
<span class="line"><span style="color:#C3E88D;">          ROUND(AVG(avg_total), 2) AS avg_order_total,</span></span>
<span class="line"><span style="color:#C3E88D;">          GROUPING(department) AS dept_grouped</span></span>
<span class="line"><span style="color:#C3E88D;">        FROM metrics</span></span>
<span class="line"><span style="color:#C3E88D;">        GROUP BY CUBE (department)</span></span>
<span class="line"><span style="color:#C3E88D;">      )</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">    SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">      a.department,</span></span>
<span class="line"><span style="color:#C3E88D;">      a.user_count,</span></span>
<span class="line"><span style="color:#C3E88D;">      a.avg_order_total,</span></span>
<span class="line"><span style="color:#C3E88D;">      SUM(a.user_count) OVER () AS total_users,</span></span>
<span class="line"><span style="color:#C3E88D;">      RANK() OVER (ORDER BY a.avg_order_total DESC NULLS LAST) AS perf_rank</span></span>
<span class="line"><span style="color:#C3E88D;">    FROM aggregates a</span></span>
<span class="line"><span style="color:#C3E88D;">    ORDER BY a.department NULLS LAST</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(rows)</span><span style="color:#89DDFF;">;</span></span></code></pre></div></details><p>Capabilities demonstrated:</p><ul><li><code>WITH</code> and writable CTEs</li><li><code>UPDATE ... RETURNING</code></li><li><code>JOIN LATERAL</code></li><li>aggregate and window functions</li><li>analytic grouping such as <code>CUBE</code> and <code>GROUPING()</code></li></ul><p>Cause and effect in this query:</p><ul><li>a writable CTE mutates and returns rows</li><li>a lateral join derives per-row metrics from that result</li><li>the final query computes aggregate and ranking outputs from the transformed relation</li></ul><hr><details><summary>Query 2: VALUES, ROWS FROM, grouping sets, and set operations</summary><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> rows </span><span style="color:#89DDFF;">}</span><span style="color:#89DDFF;"> =</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  \`</span><span style="color:#C3E88D;">WITH</span></span>
<span class="line"><span style="color:#C3E88D;">      recent_logins AS (</span></span>
<span class="line"><span style="color:#C3E88D;">        SELECT *</span></span>
<span class="line"><span style="color:#C3E88D;">        FROM (VALUES</span></span>
<span class="line"><span style="color:#C3E88D;">          (1, &#39;2025-10-01&#39;::date),</span></span>
<span class="line"><span style="color:#C3E88D;">          (2, &#39;2025-10-15&#39;::date),</span></span>
<span class="line"><span style="color:#C3E88D;">          (3, &#39;2025-10-20&#39;::date)</span></span>
<span class="line"><span style="color:#C3E88D;">        ) AS t(user_id, last_login)</span></span>
<span class="line"><span style="color:#C3E88D;">      ),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">      generated AS (</span></span>
<span class="line"><span style="color:#C3E88D;">        SELECT *</span></span>
<span class="line"><span style="color:#C3E88D;">        FROM ROWS FROM (</span></span>
<span class="line"><span style="color:#C3E88D;">          generate_series(1, 3) AS gen_id,</span></span>
<span class="line"><span style="color:#C3E88D;">          unnest(ARRAY[&#39;A&#39;, &#39;B&#39;, &#39;C&#39;]) AS label</span></span>
<span class="line"><span style="color:#C3E88D;">        )</span></span>
<span class="line"><span style="color:#C3E88D;">      ),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">      enriched AS (</span></span>
<span class="line"><span style="color:#C3E88D;">        SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">          u.id,</span></span>
<span class="line"><span style="color:#C3E88D;">          u.name,</span></span>
<span class="line"><span style="color:#C3E88D;">          r.last_login,</span></span>
<span class="line"><span style="color:#C3E88D;">          g.label,</span></span>
<span class="line"><span style="color:#C3E88D;">          COALESCE(o.total, 0) AS total_spent</span></span>
<span class="line"><span style="color:#C3E88D;">        FROM users u</span></span>
<span class="line"><span style="color:#C3E88D;">        JOIN recent_logins r ON r.user_id = u.id</span></span>
<span class="line"><span style="color:#C3E88D;">        JOIN generated g ON g.gen_id = u.id</span></span>
<span class="line"><span style="color:#C3E88D;">        LEFT JOIN (VALUES</span></span>
<span class="line"><span style="color:#C3E88D;">          (1, 1200),</span></span>
<span class="line"><span style="color:#C3E88D;">          (2, 500),</span></span>
<span class="line"><span style="color:#C3E88D;">          (3, 900)</span></span>
<span class="line"><span style="color:#C3E88D;">        ) AS o(user_id, total) ON o.user_id = u.id</span></span>
<span class="line"><span style="color:#C3E88D;">      ),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">      grouped AS (</span></span>
<span class="line"><span style="color:#C3E88D;">        SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">          label,</span></span>
<span class="line"><span style="color:#C3E88D;">          DATE_TRUNC(&#39;month&#39;, last_login) AS login_month,</span></span>
<span class="line"><span style="color:#C3E88D;">          COUNT(*) AS active_users,</span></span>
<span class="line"><span style="color:#C3E88D;">          SUM(total_spent) AS revenue</span></span>
<span class="line"><span style="color:#C3E88D;">        FROM enriched</span></span>
<span class="line"><span style="color:#C3E88D;">        GROUP BY GROUPING SETS (</span></span>
<span class="line"><span style="color:#C3E88D;">          (label, login_month),</span></span>
<span class="line"><span style="color:#C3E88D;">          (label),</span></span>
<span class="line"><span style="color:#C3E88D;">          ()</span></span>
<span class="line"><span style="color:#C3E88D;">        )</span></span>
<span class="line"><span style="color:#C3E88D;">      )</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">    SELECT * FROM grouped</span></span>
<span class="line"><span style="color:#C3E88D;">    UNION ALL</span></span>
<span class="line"><span style="color:#C3E88D;">    SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">      label,</span></span>
<span class="line"><span style="color:#C3E88D;">      NULL AS login_month,</span></span>
<span class="line"><span style="color:#C3E88D;">      0 AS active_users,</span></span>
<span class="line"><span style="color:#C3E88D;">      0 AS revenue</span></span>
<span class="line"><span style="color:#C3E88D;">    FROM generated</span></span>
<span class="line"><span style="color:#C3E88D;">    EXCEPT</span></span>
<span class="line"><span style="color:#C3E88D;">    SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">      label,</span></span>
<span class="line"><span style="color:#C3E88D;">      NULL,</span></span>
<span class="line"><span style="color:#C3E88D;">      0,</span></span>
<span class="line"><span style="color:#C3E88D;">      0</span></span>
<span class="line"><span style="color:#C3E88D;">    FROM grouped</span></span>
<span class="line"><span style="color:#C3E88D;">    INTERSECT</span></span>
<span class="line"><span style="color:#C3E88D;">    SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">      label,</span></span>
<span class="line"><span style="color:#C3E88D;">      NULL,</span></span>
<span class="line"><span style="color:#C3E88D;">      0,</span></span>
<span class="line"><span style="color:#C3E88D;">      0</span></span>
<span class="line"><span style="color:#C3E88D;">    FROM grouped</span></span>
<span class="line"><span style="color:#C3E88D;">    ORDER BY label NULLS LAST</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(rows)</span><span style="color:#89DDFF;">;</span></span></code></pre></div></details><p>Capabilities demonstrated:</p><ul><li>inline <code>VALUES</code> tables</li><li><code>ROWS FROM</code> and set-returning functions</li><li>grouping sets</li><li>combined set operations</li><li>ordering with <code>NULLS LAST</code></li></ul><p>These examples show the shape of SQL FlashQL can execute.</p><p>They show that FlashQL is meant for real relational composition, not only toy queries.</p><h2 id="the-common-query-surface" tabindex="-1">The common query surface <a class="header-anchor" href="#the-common-query-surface" aria-label="Permalink to &quot;The common query surface&quot;">​</a></h2><p>FlashQL supports the same top-level application contract as the other LinkedQL clients:</p><ul><li><code>db.query()</code></li><li><code>db.stream()</code></li><li><code>db.transaction()</code></li><li><code>db.wal.subscribe()</code></li></ul><p>And then adds local-engine-specific capabilities such as:</p><ul><li><code>db.storageEngine</code></li><li><code>db.sync.sync()</code></li><li><code>versionStop</code></li><li><code>overwriteForward</code></li></ul><h2 id="live-queries-streams-and-wal" tabindex="-1">Live queries, streams, and WAL <a class="header-anchor" href="#live-queries-streams-and-wal" aria-label="Permalink to &quot;Live queries, streams, and WAL&quot;">​</a></h2><p>FlashQL also supports modern application data flows directly.</p><h3 id="live-queries" tabindex="-1">Live queries <a class="header-anchor" href="#live-queries" aria-label="Permalink to &quot;Live queries&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT id, name FROM public.users ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// current rows; the array keeps tracking the query as local state changes</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Use live queries when the application wants the query result itself to remain current over time.</p><p>See: <a href="/capabilities/live-queries">Live Queries</a></p><h3 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM public.big_table ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>This lets you consume large results lazily instead of buffering the full result in memory first.</p><p>Use streams when you want lazy one-time iteration instead of a fully buffered result set.</p><p>See: <a href="/capabilities/streaming">Streaming</a></p><h3 id="wal-subscriptions" tabindex="-1">WAL subscriptions <a class="header-anchor" href="#wal-subscriptions" aria-label="Permalink to &quot;WAL subscriptions&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#BABED8;"> console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(commit)</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#82AAFF;"> unsubscribe</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This observes table commits directly instead of maintaining a query-shaped live view.</p><p>Use WAL subscriptions when you care about table-level commit events directly.</p><p>See: <a href="/capabilities/changefeeds">Changefeeds</a></p><h2 id="transactions-and-mvcc" tabindex="-1">Transactions and MVCC <a class="header-anchor" href="#transactions-and-mvcc" aria-label="Permalink to &quot;Transactions and MVCC&quot;">​</a></h2><p>FlashQL is transaction-first. It exposes both a SQL-facing query surface and a lower-level storage transaction surface.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">transaction</span><span style="color:#BABED8;">(</span><span style="color:#C792EA;">async</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">tx</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#F07178;">(</span></span>
<span class="line"><span style="color:#89DDFF;">    \`</span><span style="color:#C3E88D;">INSERT INTO public.users (id, name)</span></span>
<span class="line"><span style="color:#C3E88D;">    VALUES (1, &#39;Ada&#39;)</span><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">    {</span><span style="color:#BABED8;"> tx</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#F07178;">  )</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This uses the SQL-facing query surface inside a transaction.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">transaction</span><span style="color:#BABED8;">(</span><span style="color:#C792EA;">async</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">tx</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#C792EA;">  const</span><span style="color:#BABED8;"> table</span><span style="color:#89DDFF;"> =</span><span style="color:#BABED8;"> tx</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getTable</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> namespace</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  await</span><span style="color:#BABED8;"> table</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">insert</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 1</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">Ada</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This uses the lower-level storage transaction surface directly.</p><p>Internally, FlashQL&#39;s storage engine uses versioned transactional state and WAL replay to support:</p><ul><li>isolated transactional work</li><li>live-query invalidation and diffing</li><li>version-aware replay to earlier points in history</li></ul><p>This is not incidental implementation detail. MVCC is part of why FlashQL can do several important things at once without collapsing them into one coarse state model:</p><ul><li>transactions can work against isolated versions instead of mutating shared state in place</li><li>readers and writers can preserve coherent visibility boundaries</li><li>live queries can diff and advance from versioned state transitions</li><li>persisted history can be replayed to earlier points in time</li></ul><p>In practical terms, MVCC is what lets FlashQL be both a transactional local database and a realtime engine, rather than forcing one of those concerns to weaken the other.</p><h2 id="foreign-data-and-local-first-orchestration" tabindex="-1">Foreign data and local-first orchestration <a class="header-anchor" href="#foreign-data-and-local-first-orchestration" aria-label="Permalink to &quot;Foreign data and local-first orchestration&quot;">​</a></h2><p>One of FlashQL&#39;s defining ideas is that local and remote data can belong to one query space.</p><p>FlashQL can attach foreign clients, register foreign namespaces, and expose upstream data locally through views that behave in one of three ways:</p><ul><li><code>origin</code>: federated at read time</li><li><code>materialized</code>: copied locally on sync</li><li><code>realtime</code>: copied locally and kept hot after sync</li></ul><p>Those concepts are covered in detail in:</p><ul><li><a href="/flashql/foreign-io">Federation, Materialization, and Realtime Views</a></li><li><a href="/flashql/sync">FlashQL Sync</a></li></ul><h2 id="point-in-time-boot" tabindex="-1">Point-in-time boot <a class="header-anchor" href="#point-in-time-boot" aria-label="Permalink to &quot;Point-in-time boot&quot;">​</a></h2><p>FlashQL can boot itself to a point in history – the state of the database at a certain table name and version.</p><h3 id="read-only-historical-boot" tabindex="-1">Read-only historical boot <a class="header-anchor" href="#read-only-historical-boot" aria-label="Permalink to &quot;Read-only historical boot&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> historical </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> historical</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With <code>versionStop</code>, FlashQL replays itself to the time when the database had the specified table at the specified version.</p><p>The effect is that the runtime boots against that historical boundary instead of replaying all the way forward to the latest state.</p><p>By default, that boot is read-only. Rewriting the hostory from that point forward is possible with an explicit opt-in:</p><h4 id="overwriteforward-true" tabindex="-1"><code>overwriteForward: true</code> <a class="header-anchor" href="#overwriteforward-true" aria-label="Permalink to &quot;\`overwriteForward: true\`&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> branch </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  overwriteForward</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> branch</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With <code>overwriteForward: true</code>, FlashQL keeps the history intact until the first mutating commit, then truncates forward history and lets you continue from that historical point.</p><p>That turns the historical boot into a branch point: read-only until the first write, then writable from that point forward.</p><p>See also:</p><ul><li><a href="/capabilities/version-binding">Version Binding</a></li><li><a href="/flashql/lang">FlashQL Language Reference</a></li></ul><h2 id="what-flashql-does-not-try-to-be" tabindex="-1">What FlashQL does not try to be <a class="header-anchor" href="#what-flashql-does-not-try-to-be" aria-label="Permalink to &quot;What FlashQL does not try to be&quot;">​</a></h2><p>FlashQL is ambitious, but it is still useful to say what it is not trying to do.</p><ul><li>It is not a byte-for-byte clone of PostgreSQL or MySQL.</li><li>It does not claim universal parity with every DDL and operational feature of mainstream servers.</li><li>Some schema-evolution surfaces are still catching up.</li></ul><p>The goal is application-level SQL power in places where an embeddable runtime is the right tool.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="/flashql/lang">FlashQL Language Reference</a></li><li><a href="/flashql/foreign-io">Federation, Materialization, and Realtime Views</a></li><li><a href="/flashql/sync">FlashQL Sync</a></li><li><a href="/docs/query-api">Query Interface</a></li></ul>`,105)])])}const d=a(o,[["render",p]]);export{F as __pageData,d as default};
